import React from 'react';
import { EllipsisVerticalIcon } from '@heroicons/react/24/outline';

const UserCard = ({ user, onClick }) => {
  const getStatusColor = (availability) => {
    switch (availability) {
      case 'Available': return 'text-green-500';
      case 'In meeting': return 'text-blue-500';
      case 'Out for Lunch': return 'text-yellow-500';
      case 'Focus': return 'text-purple-500';
      case 'Emergency': return 'text-red-500';
      case 'Away': return 'text-orange-500';
      case 'Offline': return 'text-gray-500';
      default: return 'text-green-500';
    }
  };

  const getStatusDotColor = (availability) => {
    switch (availability) {
      case 'Available': return 'bg-green-500';
      case 'In meeting': return 'bg-blue-500';
      case 'Out for Lunch': return 'bg-yellow-500';
      case 'Focus': return 'bg-purple-500';
      case 'Emergency': return 'bg-red-500';
      case 'Away': return 'bg-orange-500';
      case 'Offline': return 'bg-gray-500';
      default: return 'bg-green-500';
    }
  };

  // Função para selecionar ícones aleatórios
  const getRandomIcons = () => {
    const allIcons = [
      'https://www.svgrepo.com/show/303108/figma-1-logo.svg',
      'https://upload.wikimedia.org/wikipedia/commons/7/7e/Gmail_icon_%282020%29.svg',
      'https://upload.wikimedia.org/wikipedia/commons/9/9b/Google_Meet_icon_%282020%29.svg',
      'https://www.svgrepo.com/show/353935/jira.svg',
      'https://upload.wikimedia.org/wikipedia/commons/c/c9/Microsoft_Office_Teams_%282018%E2%80%93present%29.svg',
      'https://www.svgrepo.com/show/353597/confluence.svg',
      'https://www.svgrepo.com/show/354463/trello.svg'
    ];

    // Randomizar quantidade de ícones (0 a 5)
    const iconCount = Math.floor(Math.random() * 6);

    if (iconCount === 0) {
      return [];
    }

    // Embaralhar e pegar a quantidade desejada
    const shuffled = [...allIcons].sort(() => 0.5 - Math.random());
    return shuffled.slice(0, iconCount);
  };

  return (
    <div 
      className="bg-transparent border border-neutral-700 rounded-lg p-4 cursor-pointer transition-all duration-200 hover:bg-neutral-900 hover:border-gray-600"
      onClick={onClick}
    >
      {/* Header com avatar, nome, cargo e menu */}
      <div className="flex items-start gap-3 mb-3">
        <div className="relative">
          <img 
            src={user.avatar} 
            alt={`${user.name} Profile`} 
            className="w-9 h-9 rounded-full object-cover"
          />
          <div className={`absolute -bottom-0.5 -right-0.5 w-2.5 h-2.5 ${getStatusDotColor(user.availability)} rounded-full border-2 border-gray-900`}></div>
        </div>
        <div className="flex-1">
          <h3 className="text-white font-medium text-base">{user.name}</h3>
          <div className="flex items-center gap-2">
            <p className="text-neutral-400 text-sm">{user.title}</p>
            <span className="text-neutral-400 text-sm">• 2h</span>
          </div>
        </div>
        <EllipsisVerticalIcon className="w-5 h-5 text-neutral-400" />
      </div>

      {/* Atividade atual - truncada em 1 linha */}
      <div className="mb-3">
        <p className="text-white text-sm truncate">{user.bio}</p>
      </div>

      {/* Badge de status */}
      <div className="flex items-center gap-2">
        <div className={`border border-neutral-700 rounded px-2 pb-1 ${getStatusColor(user.availability)}`}>
          <span className="text-xs font-medium">{user.availability}</span>
        </div>
        {/* Ícone do app */}
        <img 
          src={getRandomIcon()} 
          alt="App icon" 
          className="w-5 h-5 object-contain"
        />
      </div>
    </div>
  );
};

export default UserCard;
